messages.content:
{
  "intent": "check_and_fix",
  "intent_description": "Server 172.16.0.12 is unreachable (25 pings sent, 0 successful); goal: restore ICMP connectivity from the presumed source by fixing R2-side connectivity/ARP/interface issues.",
  "target": "router2",
  "needs_fix": true,
  "plan": {
    "problem": "172.16.0.12 not responding to ICMP (25/25 lost). Missing information: source device/IP and timestamp of the ping test; raw ping and traceroute outputs; R2 (172.16.0.1) show ip arp 172.16.0.12; R2 interface status for GigabitEthernet0/0.",
    "fix_summary": "On router2 (R2, 172.16.0.1): 1) clear stale ARP for 172.16.0.12; 2) ensure GigabitEthernet0/0 is administratively up.",
    "plan_steps": [
      {
        "id": 1,
        "device": "router2",
        "action": "clear_arp_entry",
        "target": "172.16.0.12",
        "parameters": [
          "ip=172.16.0.12"
        ]
      },
      {
        "id": 2,
        "device": "router2",
        "action": "enable_interface",
        "target": "GigabitEthernet0/0",
        "parameters": [
          "admin_state=up"
        ]
      }
    ]
  }
}

